    public Object parseOHLCV(Object ohlcv, Object... optionalArgs)
    {
        //
        // spot:
        //
        //     [
        //         [
        //             "22814.01",
        //             "22937.42",
        //             "22832.57",
        //             "22937.42",
        //             "3916.58764051",
        //             "0.171199",
        //             "2982.64647063",
        //             "0.130295",
        //             33,
        //             0,
        //             "22877.449915304470460711",
        //             "MINUTE_5",
        //             1659664800000,
        //             1659665099999
        //         ]
        //     ]
        //
        // contract:
        //
        //           [
        //             "84207.02",
        //             "84320.85",
        //             "84207.02",
        //             "84253.83",
        //             "3707.5395",
        //             "44",
        //             "14",
        //             "1740770040000",
        //             "1740770099999",
        //           ],
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object ohlcvLength = Helpers.getArrayLength(ohlcv);
        Object isContract = Helpers.isEqual(ohlcvLength, 9);
        if (Helpers.isTrue(isContract))
        {
            return new java.util.ArrayList<Object>(java.util.Arrays.asList(this.safeInteger(ohlcv, 7), this.safeNumber(ohlcv, 2), this.safeNumber(ohlcv, 1), this.safeNumber(ohlcv, 0), this.safeNumber(ohlcv, 3), this.safeNumber(ohlcv, 5)));
        }
        return new java.util.ArrayList<Object>(java.util.Arrays.asList(this.safeInteger(ohlcv, 12), this.safeNumber(ohlcv, 2), this.safeNumber(ohlcv, 1), this.safeNumber(ohlcv, 0), this.safeNumber(ohlcv, 3), this.safeNumber(ohlcv, 5)));
    }

    /**
     * @method
     * @name poloniex#fetchOHLCV
     * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @see https://api-docs.poloniex.com/spot/api/public/market-data#candles
     * @see https://api-docs.poloniex.com/v3/futures/api/market/get-kline-data
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] the maximum amount of candles to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] timestamp in ms
     * @param {boolean} [params.paginate] default false, when true will automatically paginate by calling this endpoint multiple times. See in the docs all the [availble parameters](https://github.com/ccxt/ccxt/wiki/Manual#pagination-params)
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOHLCV(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object paginate = false;
            var paginateparametersVariable = this.handleOptionAndParams(parameters, "fetchOHLCV", "paginate", false);
            paginate = ((java.util.List<Object>) paginateparametersVariable).get(0);
            parameters = ((java.util.List<Object>) paginateparametersVariable).get(1);
            if (Helpers.isTrue(paginate))
            {
                return (this.fetchPaginatedCallDeterministic("fetchOHLCV", symbol, since, limit, timeframe, parameters, 500)).join();
            }
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
                put( "interval", PoloniexCore.this.safeString(PoloniexCore.this.timeframes, timeframe, timeframe) );
            }};
            Object keyStart = ((Helpers.isTrue(Helpers.GetValue(market, "spot")))) ? "startTime" : "sTime";
            Object keyEnd = ((Helpers.isTrue(Helpers.GetValue(market, "spot")))) ? "endTime" : "eTime";
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, keyStart, since);
            }
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                // limit should in between 100 and 500
                Helpers.addElementToObject(request, "limit", limit);
            }
            var requestparametersVariable = this.handleUntilOption(keyEnd, request, parameters);
            request = ((java.util.List<Object>) requestparametersVariable).get(0);
            parameters = ((java.util.List<Object>) requestparametersVariable).get(1);
            if (Helpers.isTrue(Helpers.GetValue(market, "contract")))
            {
                if (Helpers.isTrue(this.inArray(timeframe, new java.util.ArrayList<Object>(java.util.Arrays.asList("10m", "1M")))))
                {
                    throw new NotSupported((String)Helpers.add(Helpers.add(Helpers.add(Helpers.add(Helpers.add(this.id, " "), timeframe), " "), Helpers.GetValue(market, "type")), " fetchOHLCV is not supported")) ;
                }
                Object responseRaw = (this.swapPublicGetV3MarketCandles(this.extend(request, parameters))).join();
                //
                //     {
                //         code: "200",
                //         msg: "Success",
                //         data: [
                //           [
                //             "84207.02",
                //             "84320.85",
                //             "84207.02",
                //             "84253.83",
                //             "3707.5395",
                //             "44",
                //             "14",
                //             "1740770040000",
                //             "1740770099999",
                //           ],
                //
                Object data = this.safeList(responseRaw, "data");
                return this.parseOHLCVs(data, market, timeframe, since, limit);
            }
            Object response = (this.publicGetMarketsSymbolCandles(this.extend(request, parameters))).join();
            //
            //     [
            //         [
            //             "22814.01",
            //             "22937.42",
            //             "22832.57",
            //             "22937.42",
            //             "3916.58764051",
            //             "0.171199",
            //             "2982.64647063",
            //             "0.130295",
            //             33,
            //             0,
            //             "22877.449915304470460711",
            //             "MINUTE_5",
            //             1659664800000,
            //             1659665099999
            //         ]
            //     ]
            //
            return this.parseOHLCVs(response, market, timeframe, since, limit);
        });

    }

    public java.util.concurrent.CompletableFuture<Object> loadMarkets(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object reload = Helpers.getArg(optionalArgs, 0, false);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            Object markets = (super.loadMarkets(reload, parameters)).join();
            Object currenciesByNumericId = this.safeValue(this.options, "currenciesByNumericId");
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(currenciesByNumericId, null))) || Helpers.isTrue(reload)))
            {
                Helpers.addElementToObject(this.options, "currenciesByNumericId", this.indexBy(this.currencies, "numericId"));
            }
            return markets;
        });

    }

    /**
     * @method
     * @name poloniex#fetchMarkets
     * @description retrieves data on all markets for poloniex
     * @see https://api-docs.poloniex.com/spot/api/public/reference-data#symbol-information
     * @see https://api-docs.poloniex.com/v3/futures/api/market/get-all-product-info
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} an array of objects representing market data
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMarkets(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object promises = new java.util.ArrayList<Object>(java.util.Arrays.asList(this.fetchSpotMarkets(parameters), this.fetchSwapMarkets(parameters)));
            Object results = (Helpers.promiseAll(promises)).join();
            return this.arrayConcat(Helpers.GetValue(results, 0), Helpers.GetValue(results, 1));
        });

    }

