    public Object parseMarket(Object market)
    {
        if (Helpers.isTrue(Helpers.inOp(market, "ctType")))
        {
            return this.parseSwapMarket(market);
        } else
        {
            return this.parseSpotMarket(market);
        }
    }

    public Object parseSpotMarket(Object market)
    {
        Object id = this.safeString(market, "symbol");
        Object baseId = this.safeString(market, "baseCurrencyName");
        Object quoteId = this.safeString(market, "quoteCurrencyName");
        Object base = this.safeCurrencyCode(baseId);
        Object quote = this.safeCurrencyCode(quoteId);
        Object state = this.safeString(market, "state");
        Object active = Helpers.isEqual(state, "NORMAL");
        Object symbolTradeLimit = this.safeValue(market, "symbolTradeLimit");
        // these are known defaults
        final Object finalBase = base;
        return new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "symbol", Helpers.add(Helpers.add(finalBase, "/"), quote) );
            put( "base", finalBase );
            put( "quote", quote );
            put( "settle", null );
            put( "baseId", baseId );
            put( "quoteId", quoteId );
            put( "settleId", null );
            put( "type", "spot" );
            put( "spot", true );
            put( "margin", false );
            put( "swap", false );
            put( "future", false );
            put( "option", false );
            put( "active", active );
            put( "contract", false );
            put( "linear", null );
            put( "inverse", null );
            put( "contractSize", null );
            put( "expiry", null );
            put( "expiryDatetime", null );
            put( "strike", null );
            put( "optionType", null );
            put( "precision", new java.util.HashMap<String, Object>() {{
                put( "amount", PoloniexCore.this.parseNumber(PoloniexCore.this.parsePrecision(PoloniexCore.this.safeString(symbolTradeLimit, "quantityScale"))) );
                put( "price", PoloniexCore.this.parseNumber(PoloniexCore.this.parsePrecision(PoloniexCore.this.safeString(symbolTradeLimit, "priceScale"))) );
            }} );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "amount", new java.util.HashMap<String, Object>() {{
                    put( "min", PoloniexCore.this.safeNumber(symbolTradeLimit, "minQuantity") );
                    put( "max", null );
                }} );
                put( "price", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "cost", new java.util.HashMap<String, Object>() {{
                    put( "min", PoloniexCore.this.safeNumber(symbolTradeLimit, "minAmount") );
                    put( "max", null );
                }} );
            }} );
            put( "created", PoloniexCore.this.safeInteger(market, "tradableStartTime") );
            put( "info", market );
        }};
    }

    public Object parseSwapMarket(Object market)
    {
        //
        //            {
        //                "symbol": "BNB_USDT_PERP",
        //                "bAsset": ".PBNBUSDT",
        //                "bCcy": "BNB",
        //                "qCcy": "USDT",
        //                "visibleStartTime": "1620390600000",
        //                "tradableStartTime": "1620390600000",
        //                "sCcy": "USDT",
        //                "tSz": "0.001",
        //                "pxScale": "0.001,0.01,0.1,1,10",
        //                "lotSz": "1",
        //                "minSz": "1",
        //                "ctVal": "0.1",
        //                "status": "OPEN",
        //                "oDate": "1620287590000",
        //                "maxPx": "1000000",
        //                "minPx": "0.001",
        //                "maxQty": "1000000",
        //                "minQty": "1",
        //                "maxLever": "50",
        //                "lever": "10",
        //                "ctType": "LINEAR",
        //                "alias": "",
        //                "iM": "0.02",
        //                "mM": "0.0115",
        //                "mR": "2000",
        //                "buyLmt": "",
        //                "sellLmt": "",
        //                "ordPxRange": "0.05",
        //                "marketMaxQty": "2800",
        //                "limitMaxQty": "1000000"
        //            },
        //
        Object id = this.safeString(market, "symbol");
        Object baseId = this.safeString(market, "bCcy");
        Object quoteId = this.safeString(market, "qCcy");
        Object settleId = this.safeString(market, "sCcy");
        Object base = this.safeCurrencyCode(baseId);
        Object quote = this.safeCurrencyCode(quoteId);
        Object settle = this.safeCurrencyCode(settleId);
        Object status = this.safeString(market, "status");
        Object active = Helpers.isEqual(status, "OPEN");
        Object linear = Helpers.isEqual(Helpers.GetValue(market, "ctType"), "LINEAR");
        Object symbol = Helpers.add(Helpers.add(base, "/"), quote);
        if (Helpers.isTrue(linear))
        {
            symbol = Helpers.add(symbol, Helpers.add(":", settle));
        } else
        {
            // actually, exchange does not have any inverse future now
            symbol = Helpers.add(symbol, Helpers.add(":", base));
        }
        Object alias = this.safeString(market, "alias");
        Object type = "swap";
        if (Helpers.isTrue(!Helpers.isEqual(alias, null)))
        {
            type = "future";
        }
        Object marketType = ((Helpers.isTrue((Helpers.isEqual(type, "future"))))) ? "future" : "swap";
        final Object finalSymbol = symbol;
        final Object finalBase = base;
        final Object finalType = type;
        return new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "symbol", finalSymbol );
            put( "base", finalBase );
            put( "quote", quote );
            put( "settle", settle );
            put( "baseId", baseId );
            put( "quoteId", quoteId );
            put( "settleId", settleId );
            put( "type", marketType );
            put( "spot", false );
            put( "margin", false );
            put( "swap", Helpers.isEqual(finalType, "swap") );
            put( "future", Helpers.isEqual(finalType, "future") );
            put( "option", false );
            put( "active", active );
            put( "contract", true );
            put( "linear", linear );
            put( "inverse", !Helpers.isTrue(linear) );
            put( "contractSize", PoloniexCore.this.safeNumber(market, "ctVal") );
            put( "expiry", null );
            put( "expiryDatetime", null );
            put( "strike", null );
            put( "optionType", null );
            put( "taker", PoloniexCore.this.safeNumber(market, "tFee") );
            put( "maker", PoloniexCore.this.safeNumber(market, "mFee") );
            put( "precision", new java.util.HashMap<String, Object>() {{
                put( "amount", PoloniexCore.this.safeNumber(market, "lotSz") );
                put( "price", PoloniexCore.this.safeNumber(market, "tSz") );
            }} );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "amount", new java.util.HashMap<String, Object>() {{
                    put( "min", PoloniexCore.this.safeNumber(market, "minSz") );
                    put( "max", PoloniexCore.this.safeNumber(market, "limitMaxQty") );
                }} );
                put( "price", new java.util.HashMap<String, Object>() {{
                    put( "min", PoloniexCore.this.safeNumber(market, "minPx") );
                    put( "max", PoloniexCore.this.safeNumber(market, "maxPx") );
                }} );
                put( "cost", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "leverage", new java.util.HashMap<String, Object>() {{
                    put( "max", PoloniexCore.this.safeNumber(market, "maxLever") );
                    put( "min", null );
                }} );
            }} );
            put( "created", PoloniexCore.this.safeInteger(market, "oDate") );
            put( "info", market );
        }};
    }

