    public Object parseCurrency(Object currency)
    {
        Object entry = currency;
        Object id = this.safeString(entry, "coin");
        Object code = this.safeCurrencyCode(id);
        Object networks = new java.util.HashMap<String, Object>() {{}};
        Object chains = this.safeList(entry, "networkList", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object chainsLength = Helpers.getArrayLength(chains);
        for (var j = 0; Helpers.isLessThan(j, chainsLength); j++)
        {
            Object chain = Helpers.GetValue(chains, j);
            Object chainId = this.safeString(chain, "blockchain");
            Object networkCode = this.networkIdToCode(chainId, code);
            Helpers.addElementToObject(networks, networkCode, new java.util.HashMap<String, Object>() {{
    put( "info", chain );
    put( "id", chainId );
    put( "name", null );
    put( "code", networkCode );
    put( "active", null );
    put( "fee", PoloniexCore.this.safeNumber(chain, "withdrawFee") );
    put( "deposit", PoloniexCore.this.safeBool(chain, "depositEnable") );
    put( "withdraw", PoloniexCore.this.safeBool(chain, "withdrawalEnable") );
    put( "precision", PoloniexCore.this.parseNumber(PoloniexCore.this.parsePrecision(PoloniexCore.this.safeString(chain, "decimals"))) );
    put( "limits", new java.util.HashMap<String, Object>() {{
        put( "withdraw", new java.util.HashMap<String, Object>() {{
            put( "min", PoloniexCore.this.safeNumber(chain, "withdrawMin") );
            put( "max", null );
        }} );
        put( "deposit", new java.util.HashMap<String, Object>() {{
            put( "min", null );
            put( "max", null );
        }} );
    }} );
}});
        }
        return this.safeCurrencyStructure(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "name", PoloniexCore.this.safeString(entry, "name") );
            put( "code", code );
            put( "type", null );
            put( "precision", null );
            put( "info", entry );
            put( "networks", networks );
            put( "deposit", null );
            put( "withdraw", null );
            put( "active", null );
            put( "fee", null );
            put( "limits", null );
            put( "margin", PoloniexCore.this.safeBool(entry, "supportBorrow") );
        }});
    }

