    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades
        //
        //  spot:
        //
        //     {
        //         "id" : "60014521",
        //         "price" : "23162.94",
        //         "quantity" : "0.00009",
        //         "amount" : "2.0846646",
        //         "takerSide" : "SELL",
        //         "ts" : 1659684602042,
        //         "createTime" : 1659684602036
        //     }
        //
        //   swap:
        //
        //     {
        //         "id": "105807376",
        //         "side": "buy",
        //         "px": "84410.57",
        //         "qty": "1",
        //         "amt": "84.41057",
        //         "cT": "1740777563557",
        //     }
        //
        // fetchMyTrades
        //
        //  spot:
        //
        //     {
        //         "id": "32164924331503616",
        //         "symbol": "LINK_USDT",
        //         "accountType": "SPOT",
        //         "orderId": "32164923987566592",
        //         "side": "SELL",
        //         "type": "MARKET",
        //         "matchRole": "TAKER",
        //         "createTime": 1648635115525,
        //         "price": "11",
        //         "quantity": "0.5",
        //         "amount": "5.5",
        //         "feeCurrency": "USDT",
        //         "feeAmount": "0.007975",
        //         "pageId": "32164924331503616",
        //         "clientOrderId": "myOwnId-321"
        //     }
        //
        //  swap:
        //
        //     {
        //         "symbol": "BTC_USDT_PERP",
        //         "trdId": "105813553",
        //         "side": "SELL",
        //         "type": "TRADE",
        //         "mgnMode": "CROSS",
        //         "ordType": "MARKET",
        //         "clOrdId": "polo418912106147315112",
        //         "role": "TAKER",
        //         "px": "84704.9",
        //         "qty": "1",
        //         "cTime": "1740842829430",
        //         "uTime": "1740842829450",
        //         "feeCcy": "USDT",
        //         "feeAmt": "0.04235245",
        //         "deductCcy": "",
        //         "deductAmt": "0",
        //         "feeRate": "0.0005",
        //         "id": "418912106342654592",
        //         "posSide": "BOTH",
        //         "ordId": "418912106147315112",
        //         "qCcy": "USDT",
        //         "value": "84.7049",
        //         "actType": "TRADING"
        //     },
        //
        // fetchOrderTrades (taker trades)
        //
        //     {
        //         "id": "30341456333942784",
        //         "symbol": "LINK_USDT",
        //         "accountType": "SPOT",
        //         "orderId": "30249408733945856",
        //         "side": "BUY",
        //         "type": "LIMIT",
        //         "matchRole": "MAKER",
        //         "createTime": 1648200366864,
        //         "price": "3.1",
        //         "quantity": "1",
        //         "amount": "3.1",
        //         "feeCurrency": "LINK",
        //         "feeAmount": "0.00145",
        //         "pageId": "30341456333942784",
        //         "clientOrderId": ""
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeStringN(trade, new java.util.ArrayList<Object>(java.util.Arrays.asList("id", "tradeID", "trdId")));
        Object orderId = this.safeString2(trade, "orderId", "ordId");
        Object timestamp = this.safeIntegerN(trade, new java.util.ArrayList<Object>(java.util.Arrays.asList("ts", "createTime", "cT", "cTime")));
        Object marketId = this.safeString(trade, "symbol");
        market = this.safeMarket(marketId, market, "_");
        Object symbol = Helpers.GetValue(market, "symbol");
        Object side = this.safeStringLower2(trade, "side", "takerSide");
        Object fee = null;
        Object priceString = this.safeString2(trade, "price", "px");
        Object amountString = this.safeString2(trade, "quantity", "qty");
        Object costString = this.safeString2(trade, "amount", "amt");
        Object feeCurrencyId = this.safeString2(trade, "feeCurrency", "feeCcy");
        Object feeCostString = this.safeString2(trade, "feeAmount", "feeAmt");
        if (Helpers.isTrue(!Helpers.isEqual(feeCostString, null)))
        {
            Object feeCurrencyCode = this.safeCurrencyCode(feeCurrencyId);
            final Object finalFeeCostString = feeCostString;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCostString );
                put( "currency", feeCurrencyCode );
            }};
        }
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "info", trade );
            put( "timestamp", timestamp );
            put( "datetime", PoloniexCore.this.iso8601(timestamp) );
            put( "symbol", symbol );
            put( "order", orderId );
            put( "type", PoloniexCore.this.safeStringLower2(trade, "ordType", "type") );
            put( "side", side );
            put( "takerOrMaker", PoloniexCore.this.safeStringLower2(trade, "matchRole", "role") );
            put( "price", priceString );
            put( "amount", amountString );
            put( "cost", costString );
            put( "fee", finalFee );
        }}, market);
    }

    /**
     * @method
     * @name poloniex#fetchTrades
     * @description get the list of most recent trades for a particular symbol
     * @see https://api-docs.poloniex.com/spot/api/public/market-data#trades
     * @see https://api-docs.poloniex.com/v3/futures/api/market/get-execution-info
     * @param {string} symbol unified symbol of the market to fetch trades for
     * @param {int} [since] timestamp in ms of the earliest trade to fetch
     * @param {int} [limit] the maximum amount of trades to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {Trade[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=public-trades}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTrades(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object since = Helpers.getArg(optionalArgs, 0, null);
            Object limit = Helpers.getArg(optionalArgs, 1, null);
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", limit); // max 1000, for spot & swap
            }
            if (Helpers.isTrue(Helpers.GetValue(market, "contract")))
            {
                Object response = (this.swapPublicGetV3MarketTrades(this.extend(request, parameters))).join();
                //
                //     {
                //         code: "200",
                //         msg: "Success",
                //         data: [
                //         {
                //             id: "105807320", // descending order
                //             side: "sell",
                //             px: "84383.93",
                //             qty: "1",
                //             amt: "84.38393",
                //             cT: "1740777074704",
                //         },
                //
                Object tradesList = this.safeList(response, "data");
                return this.parseTrades(tradesList, market, since, limit);
            }
            Object trades = (this.publicGetMarketsSymbolTrades(this.extend(request, parameters))).join();
            //
            //     [
            //         {
            //             "id" : "60014521",
            //             "price" : "23162.94",
            //             "quantity" : "0.00009",
            //             "amount" : "2.0846646",
            //             "takerSide" : "SELL",
            //             "ts" : 1659684602042,
            //             "createTime" : 1659684602036
            //         }
            //     ]
            //
            return this.parseTrades(trades, market, since, limit);
        });

    }

    /**
     * @method
     * @name poloniex#fetchMyTrades
     * @description fetch all trades made by the user
     * @see https://api-docs.poloniex.com/spot/api/private/trade#trade-history
     * @see https://api-docs.poloniex.com/v3/futures/api/trade/get-execution-details
     * @param {string} symbol unified market symbol
     * @param {int} [since] the earliest time in ms to fetch trades for
     * @param {int} [limit] the maximum number of trades structures to retrieve
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] the latest time in ms to fetch entries for
     * @param {boolean} [params.paginate] default false, when true will automatically paginate by calling this endpoint multiple times. See in the docs all the [availble parameters](https://github.com/ccxt/ccxt/wiki/Manual#pagination-params)
     * @returns {Trade[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=trade-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMyTrades(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object paginate = false;
            var paginateparametersVariable = this.handleOptionAndParams(parameters, "fetchMyTrades", "paginate");
            paginate = ((java.util.List<Object>) paginateparametersVariable).get(0);
            parameters = ((java.util.List<Object>) paginateparametersVariable).get(1);
            if (Helpers.isTrue(paginate))
            {
                return (this.fetchPaginatedCallDynamic("fetchMyTrades", symbol, since, limit, parameters)).join();
            }
            Object market = null;
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                market = this.market(symbol);
            }
            Object marketType = null;
            var marketTypeparametersVariable = this.handleMarketTypeAndParams("fetchMyTrades", market, parameters);
            marketType = ((java.util.List<Object>) marketTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marketTypeparametersVariable).get(1);
            Object isContract = this.inArray(marketType, new java.util.ArrayList<Object>(java.util.Arrays.asList("swap", "future")));
            Object request = new java.util.HashMap<String, Object>() {{}};
            Object startKey = ((Helpers.isTrue(isContract))) ? "sTime" : "startTime";
            Object endKey = ((Helpers.isTrue(isContract))) ? "eTime" : "endTime";
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, startKey, since);
            }
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", limit);
            }
            if (Helpers.isTrue(Helpers.isTrue(isContract) && Helpers.isTrue(!Helpers.isEqual(symbol, null))))
            {
                Helpers.addElementToObject(request, "symbol", this.safeString(market, "id"));
            }
            var requestparametersVariable = this.handleUntilOption(endKey, request, parameters);
            request = ((java.util.List<Object>) requestparametersVariable).get(0);
            parameters = ((java.util.List<Object>) requestparametersVariable).get(1);
            if (Helpers.isTrue(isContract))
            {
                Object raw = (this.swapPrivateGetV3TradeOrderTrades(this.extend(request, parameters))).join();
                //
                //    {
                //        "code": "200",
                //        "msg": "",
                //        "data": [
                //            {
                //                "symbol": "BTC_USDT_PERP",
                //                "trdId": "105813553",
                //                "side": "SELL",
                //                "type": "TRADE",
                //                "mgnMode": "CROSS",
                //                "ordType": "MARKET",
                //                "clOrdId": "polo418912106147315112",
                //                "role": "TAKER",
                //                "px": "84704.9",
                //                "qty": "1",
                //                "cTime": "1740842829430",
                //                "uTime": "1740842829450",
                //                "feeCcy": "USDT",
                //                "feeAmt": "0.04235245",
                //                "deductCcy": "",
                //                "deductAmt": "0",
                //                "feeRate": "0.0005",
                //                "id": "418912106342654592",
                //                "posSide": "BOTH",
                //                "ordId": "418912106147315112",
                //                "qCcy": "USDT",
                //                "value": "84.7049",
                //                "actType": "TRADING"
                //            },
                //
                Object data = this.safeList(raw, "data");
                return this.parseTrades(data, market, since, limit);
            }
            Object response = (this.privateGetTrades(this.extend(request, parameters))).join();
            //
            //     [
            //         {
            //             "id": "32164924331503616",
            //             "symbol": "LINK_USDT",
            //             "accountType": "SPOT",
            //             "orderId": "32164923987566592",
            //             "side": "SELL",
            //             "type": "MARKET",
            //             "matchRole": "TAKER",
            //             "createTime": 1648635115525,
            //             "price": "11",
            //             "quantity": "0.5",
            //             "amount": "5.5",
            //             "feeCurrency": "USDT",
            //             "feeAmount": "0.007975",
            //             "pageId": "32164924331503616",
            //             "clientOrderId": "myOwnId-321"
            //         }
            //     ]
            //
            Object result = this.parseTrades(response, market, since, limit);
            return result;
        });

    }

    public Object parseOrderStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "NEW", "open" );
            put( "PARTIALLY_FILLED", "open" );
            put( "FILLED", "closed" );
            put( "PENDING_CANCEL", "canceled" );
            put( "PARTIALLY_CANCELED", "canceled" );
            put( "CANCELED", "canceled" );
            put( "FAILED", "canceled" );
        }};
        return this.safeString(statuses, status, status);
    }

