    public Object parseLeverage(Object leverage, Object... optionalArgs)
    {
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object shortLeverage = null;
        Object longLeverage = null;
        Object marketId = null;
        Object marginMode = null;
        Object data = this.safeList(leverage, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
        {
            Object entry = Helpers.GetValue(data, i);
            marketId = this.safeString(entry, "symbol");
            marginMode = this.safeString(entry, "mgnMode");
            Object lever = this.safeInteger(entry, "lever");
            Object posSide = this.safeString(entry, "posSide");
            if (Helpers.isTrue(Helpers.isEqual(posSide, "LONG")))
            {
                longLeverage = lever;
            } else if (Helpers.isTrue(Helpers.isEqual(posSide, "SHORT")))
            {
                shortLeverage = lever;
            } else
            {
                longLeverage = lever;
                shortLeverage = lever;
            }
        }
        final Object finalMarketId = marketId;
        final Object finalMarginMode = marginMode;
        final Object finalLongLeverage = longLeverage;
        final Object finalShortLeverage = shortLeverage;
        return new java.util.HashMap<String, Object>() {{
            put( "info", leverage );
            put( "symbol", PoloniexCore.this.safeSymbol(finalMarketId, market) );
            put( "marginMode", finalMarginMode );
            put( "longLeverage", finalLongLeverage );
            put( "shortLeverage", finalShortLeverage );
        }};
    }

